/**
 * ACPX Mission Type Contracts
 * Minimal type definitions for mission scaffolding and execution.
 */

// -----------------------------------------------------------------------------
// Mission Configuration
// -----------------------------------------------------------------------------

/** Mission execution parameters provided at scaffold time. */
export interface MissionConfig {
  /** Unique mission identifier. */
  readonly missionId: string;
  /** Human-readable mission name. */
  readonly name: string;
  /** Optional mission description. */
  readonly description?: string;
  /** Target environment or context. */
  readonly target?: string;
  /** Arbitrary key-value metadata. */
  readonly metadata?: Readonly<Record<string, string>>;
}

// -----------------------------------------------------------------------------
// Mission State
// -----------------------------------------------------------------------------

/** Execution state of a mission. */
export type MissionState =
  | 'pending'
  | 'running'
  | 'paused'
  | 'completed'
  | 'failed'
  | 'cancelled';

/** Tracks the current state and progress of a mission. */
export interface MissionStatus {
  /** Current execution state. */
  readonly state: MissionState;
  /** Progress percentage (0–100). */
  readonly progress: number;
  /** Timestamp of last state change (ISO 8601). */
  readonly lastUpdated: string;
  /** Optional error message when state is 'failed'. */
  readonly error?: string;
}

// -----------------------------------------------------------------------------
// Mission Result
// -----------------------------------------------------------------------------

/** Outcome of a completed or failed mission. */
export type MissionResult =
  | { readonly ok: true; readonly value: unknown }
  | { readonly ok: false; readonly error: string };

// -----------------------------------------------------------------------------
// Schema (for serialization / contract verification)
// -----------------------------------------------------------------------------

/** JSON schema descriptor for a mission artifact. */
export interface Schema {
  readonly $schema?: string;
  readonly title?: string;
  readonly type?: string;
  readonly properties?: Readonly<Record<string, Schema>>;
  readonly required?: ReadonlyArray<string>;
  readonly description?: string;
}

/** Manifest describing mission inputs and outputs. */
export interface MissionManifest {
  readonly version: string;
  readonly config: Schema;
  readonly result?: Schema;
}

